#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long L, R;
        scanf("%lld %lld", &L, &R);
        long long maxProduct = 0;
        for (long long X = L; X <= R; X++) {
            char str[20];
            sprintf(str, "%lld", X);
            int count4 = 0, count7 = 0;
            for (int i = 0; i < strlen(str); i++) {
                if (str[i] == '4') count4++;
                else if (str[i] == '7') count7++;
            }
            if (count4 * count7 > maxProduct && (count4 > 0 && count7 > 0)) maxProduct = count4 * count7;
        }
        printf("%lld\n", maxProduct);
    }
    return 0;
}

